for (const [lang, entries] of Object.entries(toastTranslationPatch)) {
  Object.assign(translations[lang], entries);
}

const indicRanges = {
  ta: /[\u0B80-\u0BFF]/,
  ml: /[\u0D00-\u0D7F]/,
  kn: /[\u0C80-\u0CFF]/,
  te: /[\u0C00-\u0C7F]/,
  hi: /[\u0900-\u097F]/,
};

function hasWrongIndicScript(language, value) {
  if (!language || language === "en" || typeof value !== "string") return false;
  return Object.entries(indicRanges).some(([scriptLanguage, range]) => (
    scriptLanguage !== language && range.test(value)
  ));
}

function resolveTranslation(language, key, fallback = "") {
  const local = translations[language]?.[key];
  if (local && !hasWrongIndicScript(language, local)) return local;
  const english = translations.en?.[key];
  return english || fallback || key;
}

const I18nContext = createContext({
  language: "en",
  setLanguage: () => {},
  t: (key, fallback = "") => fallback || key,
});

export function I18nProvider({ language, setLanguage, children }) {
  const t = useCallback((key, fallback = "") => resolveTranslation(language, key, fallback), [language]);
  const value = useMemo(() => ({
    language,
    setLanguage,
    t,
  }), [language, setLanguage, t]);
  return createElement(I18nContext.Provider, { value }, children);
}

export function useI18n() {
  return useContext(I18nContext);
}

export function getTranslation(language, key, fallback = "") {
  return resolveTranslation(language, key, fallback);
}

export function getTypeLabel(language, type, fallback = "") {
  return typeDisplayLabels[language]?.[type] || typeDisplayLabels.en[type] || fallback || type;
}

export function getCategoryLabel(language, category, fallback = "") {
  if (!category) return fallback || "";
  if (language === "en") return category;
  return financeCategoryLabels[language]?.[category] || fallback || category;
}

export function localizeKnownText(language, value) {
  if (!value || language === "en" || typeof value !== "string") return value;
  const phraseReplacements = [
    ["YOU are building wealth with solid momentum.", resolveTranslation(language, "ai.localHeadlineStrong", "You are building wealth with solid momentum.")],
    ["You are building wealth with solid momentum.", resolveTranslation(language, "ai.localHeadlineStrong", "You are building wealth with solid momentum.")],
    ["Your current pattern needs intervention before expenses crowd out progress.", resolveTranslation(language, "ai.localHeadlineIntervention", "Your current pattern needs intervention before expenses crowd out progress.")],
    ["Your cash flow is workable, but there is room to tighten execution.", resolveTranslation(language, "ai.localHeadlineWorkable", "Your cash flow is workable, but there is room to tighten execution.")],
    ["Your cash flow is workable, but the savings cushion needs attention.", resolveTranslation(language, "ai.localHeadlineWorkable", "Your cash flow is workable, but the savings cushion needs attention.")],
    ["Your spending mix is fairly balanced. Keep reinforcing the current category discipline.", resolveTranslation(language, "ai.localBalancedSpend", "Your spending mix is fairly balanced. Keep reinforcing the current category discipline.")],
    ["Savings rate is below 15%. Start by automating a transfer on salary day before discretionary spending happens.", resolveTranslation(language, "ai.localTipLowSavings", "Savings rate is below 15%. Start by automating a transfer on salary day before discretionary spending happens.")],
    ["Savings rate is healthy. Redirect part of annual bonuses and tax refunds into long-term assets.", resolveTranslation(language, "ai.localTipHealthySavings", "Savings rate is healthy. Redirect part of annual bonuses and tax refunds into long-term assets.")],
    ["Savings rate is strong. Consider layering surplus across emergency cash, retirement, and diversified growth assets.", resolveTranslation(language, "ai.localTipStrongSavings", "Savings rate is strong. Consider layering surplus across emergency cash, retirement, and diversified growth assets.")],
    ["Investment contributions are still light relative to income. A SIP target around 15-20% of income would improve compounding.", resolveTranslation(language, "ai.localTipInvestmentLight", "Investment contributions are still light relative to income. A SIP target around 15-20% of income would improve compounding.")],
    ["Investment contribution is light relative to income. Even a small SIP can keep compounding active.", resolveTranslation(language, "ai.localTipInvestmentLight", "Investment contribution is light relative to income. Even a small SIP can keep compounding active.")],
    ["Insurance outflow is meaningful. Revisit overlapping covers and premium efficiency at renewal.", resolveTranslation(language, "ai.localTipInsurance", "Insurance outflow is meaningful. Revisit overlapping covers and premium efficiency at renewal.")],
    ["Savings rate", resolveTranslation(language, "ai.savingsRate", "Savings rate")],
    ["Monthly spend", resolveTranslation(language, "ai.monthlySpend", "Monthly spend")],
    ["Investment contribution", resolveTranslation(language, "ai.investmentContribution", "Investment contribution")],
    ["Insurance outflow", resolveTranslation(language, "ai.insuranceOutflow", "Insurance outflow")],
    ["Tracked net worth", resolveTranslation(language, "ai.trackedNetWorth", "Tracked net worth")],
    ["Healthy rhythm", resolveTranslation(language, "dashboard.healthyRhythm", "Healthy rhythm")],
    ["No urgent warnings from budgets, anomalies, or recurring commitments.", resolveTranslation(language, "dashboard.healthyRhythmBody", "No urgent warnings from budgets, anomalies, or recurring commitments.")],
    ["No spend yet", resolveTranslation(language, "dashboard.noSpend", "No spend yet")],
    ["Nothing flagged", resolveTranslation(language, "dashboard.nothingFlagged", "Nothing flagged")],
    ["Needs review", resolveTranslation(language, "dashboard.needsReview", "Needs review")],
    ["Top Expense", resolveTranslation(language, "dashboard.topExpense", "Top Expense")],
    ["Recurring Outflow", resolveTranslation(language, "dashboard.recurringOutflow", "Recurring Outflow")],
    ["Unusual Spend", resolveTranslation(language, "dashboard.unusualSpend", "Unusual Spend")],
    ["Investment Allocation", resolveTranslation(language, "dashboard.investAlloc", "Investment Allocation")],
    ["Insurance Load", resolveTranslation(language, "dashboard.insuranceLoad", "Insurance Load")],
    ["Action", resolveTranslation(language, "ai.action", "Action")],
    ["Opportunity", resolveTranslation(language, "ai.opportunity", "Opportunity")],
    ["Portfolio Nudge", resolveTranslation(language, "ai.portfolioNudge", "Portfolio Nudge")],
    ["No expense data yet", resolveTranslation(language, "ai.topSpendEmpty", "No expense data yet")],
    ["No expense data for this period yet.", resolveTranslation(language, "dashboard.noExpenseData", "No expense data for this period yet.")],
    ["Bills, EMIs, and subscriptions flagged recurring.", resolveTranslation(language, "dashboard.recurringBody", "Bills, EMIs, and subscriptions flagged recurring.")],
  ];

  const phraseLocalized = phraseReplacements.reduce((text, [from, to]) => (
    to ? text.split(from).join(to) : text
  ), value);
  if (phraseLocalized !== value) return phraseLocalized;

  const trimmed = value.trim();
  const exact = knownTextLabels[trimmed]?.[language];
  return exact ? value.replace(trimmed, exact) : value;
}
